// ============================================================================
// 1) 裂光雷射砲 — locked continuous beam, hitscan tick along a line
// ============================================================================
Weapons.register({
  id: 'g_laserbeam', name: '裂光雷射砲', icon: 'weapon_g_laserbeam', tier: 3, weight: 6, maxLevel: 8,
  update(w, p, inst, dt) {
    const l = inst.level;
    inst.st.cd = inst.st.cd || new WeakMap();   // WeakMap: per-enemy hit cooldowns, GC'd with the enemy (no unbounded growth)
    inst.st.t = (inst.st.t || 0) - dt;
    inst.st.beams = inst.st.beams || [];
    // sweep target & aim
    const beams = 1 + Math.floor((l - 1) / 3);           // 1 -> up to 3 parallel/forked beams
    const range = 230 + l * 14;
    if (inst.st.t <= 0) {
      inst.st.t = 0.12;                                   // damage tick rate
      const targets = _gwbNearest(w, p.x, p.y, beams, range);
      const baseA = targets.length ? Math.atan2(targets[0].y - p.y, targets[0].x - p.x) : _gwbFace(p);
      inst.st.shots = [];
      for (let b = 0; b < beams; b++) {
        const a = targets[b] ? Math.atan2(targets[b].y - p.y, targets[b].x - p.x) : baseA + (b - (beams - 1) / 2) * 0.34;
        const ex = p.x + Math.cos(a) * range, ey = p.y + Math.sin(a) * range;
        inst.st.shots.push({ x0: p.x, y0: p.y, x1: ex, y1: ey, a });
        w.addBeam(p.x, p.y, ex, ey, P.redL);
        // hitscan: damage enemies near the segment
        const w2 = (5 + l * 0.4);                          // beam half-width
        for (const e of _gwbAlive(w)) {
          const t = Math.max(0, Math.min(1, ((e.x - p.x) * Math.cos(a) + (e.y - p.y) * Math.sin(a)) / range));
          const px = p.x + (ex - p.x) * t, py = p.y + (ey - p.y) * t;
          if (dist2(px, py, e.x, e.y) < (w2 + e.radius) ** 2) {
            const last = inst.st.cd.get(e) || 0;
            if (w.time >= last) {
              inst.st.cd.set(e, w.time + 0.1);
              const { dmg, crit } = _gwbRoll(p, 8 + l * 2.2);
              e.hurt(dmg, Math.cos(a) * 6, Math.sin(a) * 6, w, crit);
              if (Math.random() < 0.5) w.particles.spawn({ x: e.x, y: e.y, life: 0.2, size: 2, color: P.emberL, glow: true });
            }
          }
        }
      }
    }
  },
  draw(w, p, inst) {
    for (const s of (inst.st.shots || [])) {
      glowWorld(s.x1, s.y1, 7, P.redL, 0.5);
      glowWorld((s.x0 + s.x1) / 2, (s.y0 + s.y1) / 2, 6, P.red, 0.25);
    }
  },
  levelDesc: (l) => `光束 ${1 + Math.floor((l - 1) / 3)}・每跳 ${(8 + l * 2.2) | 0}・射程 ${230 + l * 14}`,
  desc: '鎖定最近敵人持續灼燒的高速雷射，高等級分裂多道光束。',
});

// ============================================================================
// 2) 十字彈幕 — cross volley (+ then x), expanding ring count
// ============================================================================
Weapons.register({
  id: 'g_crossbarrage', name: '十字彈幕', icon: 'weapon_g_crossbarrage', tier: 1, weight: 9, maxLevel: 8,
  cooldown: (l) => Math.max(0.42, 0.95 - l * 0.06),
  fire(w, p, inst) {
    const l = inst.level;
    const arms = l >= 4 ? 8 : 4;                          // + upgrades to *
    const rings = 1 + Math.floor(l / 3) + (p.stats.projCountAdd || 0); // staggered waves
    const spin = w.time * 0.6 + (l >= 6 ? 0.2 : 0);
    const sp = 220 * (p.stats.projSpeedMult || 1);
    for (let r = 0; r < rings; r++) {
      const off = r * 0.18;
      for (let i = 0; i < arms; i++) {
        const a = spin + i / arms * TAU + off;
        const { dmg, crit } = _gwbRoll(p, 7 + l * 2.4);
        w.addProjectile(new Projectile({
          x: p.x, y: p.y, vx: Math.cos(a) * sp, vy: Math.sin(a) * sp,
          damage: dmg, crit, faction: 'player', sprite: 'g_bolt_cross', color: P.blueL,
          radius: 3, pierce: Math.floor(l / 5) + (p.stats.pierceAdd || 0), life: 0.95, knockback: 14,
        }));
      }
    }
  },
  levelDesc: (l) => `${l >= 4 ? '米字 8' : '十字 4'} 向・波數 ${1 + Math.floor(l / 3)}・傷害 ${(7 + l * 2.4) | 0}`,
  desc: '以自身為中心射出十字彈幕，滿等變為米字八向多重波。',
});

// ============================================================================
// 3) 跳彈魂珠 — ricochets to the next nearest enemy on hit
// ============================================================================
Weapons.register({
  id: 'g_ricochet', name: '跳彈魂珠', icon: 'weapon_g_ricochet', tier: 2, weight: 7, maxLevel: 7,
  cooldown: (l) => Math.max(0.5, 1.15 - l * 0.09),
  fire(w, p, inst) {
    const l = inst.level;
    const shots = 1 + Math.floor(l / 3) + (p.stats.projCountAdd || 0);
    const bounces = 2 + l;                                 // remaining hops
    const base = 9 + l * 3;
    const targets = _gwbNearest(w, p.x, p.y, shots, 760);
    const sp = 250 * (p.stats.projSpeedMult || 1);
    for (let s = 0; s < shots; s++) {
      const t = targets[s % Math.max(1, targets.length)];
      const a = t ? Math.atan2(t.y - p.y, t.x - p.x) : _gwbFace(p) + (s - shots / 2) * 0.25;
      const { dmg, crit } = _gwbRoll(p, base);
      w.addProjectile(_gwbMakeBounce(p, p.x, p.y, a, sp, dmg, crit, bounces, base));
    }
  },
  levelDesc: (l) => `彈數 ${1 + Math.floor(l / 3)}・跳躍 ${2 + l} 次・傷害 ${(9 + l * 3) | 0}`,
  desc: '射出彈跳魂珠，命中後自動彈向下一個最近的敵人。',
});
function _gwbMakeBounce(p, x, y, a, sp, dmg, crit, hops, base) {
  return new Projectile({
    x, y, vx: Math.cos(a) * sp, vy: Math.sin(a) * sp,
    damage: dmg, crit, faction: 'player', sprite: 'g_bolt_ricochet', color: P.emberL,
    radius: 3.2, pierce: 0, life: 1.4, knockback: 12,
    onHit(target, world) {
      if (hops <= 0) return;
      // find next nearest enemy excluding the one just hit
      let best = null, bd = 200 * 200;
      for (const e of world.enemies) {
        if (e.dead || e.spawnT > 0 || e === target) continue;
        const d = dist2(target.x, target.y, e.x, e.y);
        if (d < bd) { bd = d; best = e; }
      }
      if (!best) return;
      const na = Math.atan2(best.y - target.y, best.x - target.x);
      const { dmg: nd, crit: nc } = _gwbRoll(p, base * 0.92);
      const nb = _gwbMakeBounce(p, target.x, target.y, na, sp, nd, nc, hops - 1, base);
      nb.hitSet.add(target);
      world.addProjectile(nb);
      world.particles.spawn({ x: target.x, y: target.y, life: 0.18, size: 2.4, color: P.gold, glow: true });
    },
  });
}

// ============================================================================
// 4) 虛空黑洞 — singularity that pulls enemies in and ticks damage
// ============================================================================
Weapons.register({
  id: 'g_blackhole', name: '虛空黑洞', icon: 'weapon_g_blackhole', tier: 3, weight: 5, maxLevel: 6,
  cooldown: (l) => Math.max(3.2, 5.4 - l * 0.4),
  fire(w, p, inst) {
    const l = inst.level;
    inst.st.holes = inst.st.holes || [];
    const t = _gwbNearest(w, p.x, p.y, 1, 360)[0];
    const ang = _gwbFace(p);
    const hx = t ? t.x : p.x + Math.cos(ang) * 90;
    const hy = t ? t.y : p.y + Math.sin(ang) * 90;
    inst.st.holes.push({
      x: hx, y: hy, life: 2.0 + l * 0.25, max: 2.0 + l * 0.25,
      R: (54 + l * 8) * (p.stats.area || 1), pull: 140 + l * 16,
      dps: 6 + l * 3, tick: 0,
    });
    w.particles.ring(hx, hy, P.purpleL, 18, 70);
  },
  update(w, p, inst, dt) {
    const holes = inst.st.holes; if (!holes || !holes.length) return;
    for (let i = holes.length - 1; i >= 0; i--) {
      const h = holes[i];
      h.life -= dt;
      if (h.life <= 0) {
        // collapse burst
        const { dmg } = _gwbRoll(p, 18 + inst.level * 6);
        w.spawnExplosion(h.x, h.y, h.R * 0.7, P.manaL, dmg, { knockback: 120 });
        holes.splice(i, 1);
        continue;
      }
      h.tick -= dt;
      const doTick = h.tick <= 0;
      if (doTick) h.tick = 0.2;
      for (const e of _gwbAlive(w)) {
        const dx = h.x - e.x, dy = h.y - e.y;
        const d = Math.hypot(dx, dy) || 1;
        if (d < h.R) {
          // pull toward centre (respect knockback resist a bit)
          const f = h.pull * (1 - d / h.R) * dt / d;
          const kr = 1 - (e.knockbackResist || 0) * 0.6;
          e.x += dx * f * kr; e.y += dy * f * kr;
          if (doTick) {
            const { dmg, crit } = _gwbRoll(p, h.dps);
            e.hurt(dmg, 0, 0, w, crit);
          }
        }
      }
    }
  },
  draw(w, p, inst) {
    const holes = inst.st.holes; if (!holes) return;
    for (const h of holes) {
      const k = Math.max(0, Math.min(1, h.life / h.max));
      fillCircleWorld(h.x, h.y, h.R, withAlpha(P.void, 0.12));
      fillCircleWorld(h.x, h.y, 6 + (1 - k) * 3, withAlpha(P.ink, 0.85));
      glowWorld(h.x, h.y, h.R * 0.6, P.purpleL, 0.18 + (1 - k) * 0.1);
      if (Math.random() < 0.6) {
        const a = Math.random() * TAU, rr = h.R * (0.6 + Math.random() * 0.4);
        w.particles.spawn({ x: h.x + Math.cos(a) * rr, y: h.y + Math.sin(a) * rr, vx: -Math.cos(a) * 40, vy: -Math.sin(a) * 40, life: 0.35, size: 2, color: P.manaL, glow: true, drag: 0.92 });
      }
    }
  },
  levelDesc: (l) => `半徑 ${(54 + l * 8) | 0}・每秒 ${((6 + l * 3) * 5) | 0}・崩塌爆傷 ${(18 + l * 6) | 0}`,
  desc: '撕裂虛空生成黑洞，持續吸引並絞碎敵人，消散時引爆。',
});

// ============================================================================
// 5) 神聖光輪 — orbiting holy halos that smite on contact
// ============================================================================
Weapons.register({
  id: 'g_halo', name: '神聖光輪', icon: 'weapon_g_halo', tier: 2, weight: 7, maxLevel: 6,
  update(w, p, inst, dt) {
    const l = inst.level;
    const n = 2 + Math.floor(l * 0.8);
    const R = (32 + l * 4) * (p.stats.area || 1);
    inst.st.a = (inst.st.a || 0) + dt * 2.2;
    inst.st.cd = inst.st.cd || new WeakMap();   // WeakMap: per-enemy hit cooldowns, GC'd with the enemy (no unbounded growth)
    for (let i = 0; i < n; i++) {
      const a = inst.st.a + i / n * TAU;
      const ox = p.x + Math.cos(a) * R, oy = p.y + Math.sin(a) * R;
      for (const e of _gwbAlive(w)) {
        if (dist2(ox, oy, e.x, e.y) < (e.radius + 7) ** 2) {
          const key = e;
          const last = inst.st.cd.get(key) || 0;
          if (w.time >= last) {
            inst.st.cd.set(key, w.time + 0.3);
            const { dmg, crit } = _gwbRoll(p, 8 + l * 4.2);
            const ka = Math.atan2(e.y - p.y, e.x - p.x);
            e.hurt(dmg, Math.cos(ka) * 26, Math.sin(ka) * 26, w, crit);
            w.particles.spawn({ x: ox, y: oy, life: 0.2, size: 2.4, color: P.goldL, glow: true });
          }
        }
      }
    }
  },
  draw(w, p, inst) {
    const l = inst.level;
    const n = 2 + Math.floor(l * 0.8);
    const R = (32 + l * 4) * (p.stats.area || 1);
    const sp = getSprite('g_fx_halo');
    for (let i = 0; i < n; i++) {
      const a = (inst.st.a || 0) + i / n * TAU;
      const ox = p.x + Math.cos(a) * R, oy = p.y + Math.sin(a) * R;
      glowWorld(ox, oy, 7, P.goldL, 0.4);
      drawSprite(sp.frames[0], ox, oy, { ax: sp.ax, ay: sp.ay, rot: a });
    }
  },
  levelDesc: (l) => `光輪 ${2 + Math.floor(l * 0.8)}・半徑 ${(32 + l * 4) | 0}・觸擊 ${(8 + l * 4.2) | 0}`,
  desc: '召喚環繞自身的神聖光輪，碰觸即制裁周圍敵人。',
});

// ============================================================================
// 6) 飛鏢扇 — spread of piercing spinning darts toward facing/nearest
// ============================================================================
Weapons.register({
  id: 'g_dartfan', name: '飛鏢扇', icon: 'weapon_g_dartfan', tier: 1, weight: 8, maxLevel: 8,
  cooldown: (l) => Math.max(0.46, 0.9 - l * 0.055),
  fire(w, p, inst) {
    const l = inst.level;
    const count = 3 + Math.floor(l * 0.7) + (p.stats.projCountAdd || 0);
    const spread = 0.7 + l * 0.05;
    const t = _gwbNearest(w, p.x, p.y, 1, 620)[0];
    const base = t ? Math.atan2(t.y - p.y, t.x - p.x) : _gwbFace(p);
    const sp = 235 * (p.stats.projSpeedMult || 1);
    for (let i = 0; i < count; i++) {
      const a = base + (count > 1 ? (i / (count - 1) - 0.5) * spread : 0);
      const { dmg, crit } = _gwbRoll(p, 6 + l * 2.1);
      w.addProjectile(new Projectile({
        x: p.x, y: p.y, vx: Math.cos(a) * sp, vy: Math.sin(a) * sp,
        damage: dmg, crit, faction: 'player', sprite: 'g_dart', color: P.shardL,
        radius: 3, pierce: 1 + Math.floor(l / 3) + (p.stats.pierceAdd || 0), life: 0.85,
        knockback: 10, spin: 18,
      }));
    }
  },
  levelDesc: (l) => `飛鏢 ${3 + Math.floor(l * 0.7)}・穿透 ${1 + Math.floor(l / 3)}・傷害 ${(6 + l * 2.1) | 0}`,
  desc: '朝最近敵人扇形擲出旋轉飛鏢，貫穿成排目標。',
});

